import React, { createContext, useContext, useState, useEffect, useMemo } from 'react';

const ThemeContext = createContext();

export const ThemeProvider = ({ children }) => {
  // 1. Initialize state from localStorage or System Preference
  const [theme, setTheme] = useState(() => {
    const savedTheme = localStorage.getItem('terminal_theme');
    if (savedTheme) return savedTheme;
    
    // Fallback to system preference (Dark by default for the terminal)
    return window.matchMedia('(prefers-color-scheme: light)').matches ? 'light' : 'dark';
  });

  const isDarkMode = theme === 'dark';

  // 2. Toggle Protocol
  const toggleTheme = () => {
    const newTheme = isDarkMode ? 'light' : 'dark';
    setTheme(newTheme);
    localStorage.setItem('terminal_theme', newTheme);
  };

  // 3. Apply Theme to the Document Root
  useEffect(() => {
    const root = window.document.documentElement;
    
    // Remove both classes to ensure a clean state
    root.classList.remove('light', 'dark');
    root.classList.add(theme);
    
    // Optional: Setting a data attribute for specific CSS selection
    root.setAttribute('data-theme', theme);
  }, [theme]);

  // 4. Memoize the value to prevent unnecessary re-renders of the entire app tree
  const value = useMemo(() => ({
    theme,
    isDarkMode,
    toggleTheme
  }), [theme, isDarkMode]);

  return (
    <ThemeContext.Provider value={value}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) {
    throw new Error('useTheme must be used within a ThemeProvider node.');
  }
  return context;
};
